<template>
  <div class="sms_signatures_edit">
    <h4>新增短信模組</h4>
    <el-form ref="form" :model="form" :rules="rules" label-width="150px" class="demo-ruleForm">
      <el-form-item label="短信類型" prop="template_type">
        <el-radio-group v-model="form.template_type" :disabled="disabled">
          <el-radio label="0"> 驗證碼（0.045元 / 條） </el-radio>
          <el-radio label="1"> 短信通知（0.045元 / 條） </el-radio>
          <el-radio v-if="!VERSION_IN_PURCHASE" label="2"> 推廣短信（0.055元 / 條） </el-radio>
        </el-radio-group>
      </el-form-item>
      <el-form-item v-if="form.template_type" label="短信場景" prop="scene_id">
        <el-select
          v-model="form.scene_id"
          placeholder="請選擇"
          style="width: 400px"
          :disabled="disabled"
        >
          <el-option
            v-for="item in template_type_options"
            :key="item.id"
            :label="item.scene_name"
            :value="item.id"
          />
        </el-select>
      </el-form-item>
      <el-form-item label="模組名稱" prop="template_name">
        <el-input
          v-model="form.template_name"
          :disabled="disabled"
          minlength="1"
          maxlength="30"
          show-word-limit
          placeholder="長度限1-30個字符"
        />
      </el-form-item>
      <el-form-item label="模組內容" prop="template_content">
        <nav>
          <span
            v-for="item in variables"
            :key="item.var_name"
            :class="['key', { 'detail': $route.query.type == 'detail' }]"
            @click="fnKey(item)"
            >${ {{ item.var_title }} }</span
          >
        </nav>
        <el-input
          v-model="form.template_content"
          :disabled="disabled"
          type="textarea"
          :rows="8"
          maxlength="500"
          show-word-limit
          placeholder="短信模組申請說明，請描述您的業務使用場景，長度為1-500個字符。"
        />
        <ul class="tips">
          <li>
            短信字數含 " 簽名 + 模版內容 + 變量內容”，短信 70 個字數含以內，按 1 條短信計費；超出 70
            個字為長短信，按照 67 個字數記為 1 條短信費用。
          </li>
          <li>
            短信服務的模組都需要經過審核，審核通過後才可以使用該模組，請參見
            <a
              target="_blank"
              href="https://help.aliyun.com/document_detail/108253.htm?spm=a2c4g.11186623.0.0.7c8e2918ZCtnlV"
              >短信模組規範。</a
            >
          </li>
        </ul>
      </el-form-item>
      <el-form-item label="申請說明" prop="remark">
        <el-input
          v-model="form.remark"
          :disabled="disabled"
          type="textarea"
          :rows="4"
          maxlength="100"
          show-word-limit
          placeholder="短信模組申請說明，請描述您的業務使用場景，長度為1-100個字符。"
        />
      </el-form-item>
      <el-form-item v-if="$route.query.type !== 'detail'">
        <!-- <el-button type="primary" @click="submitForm('form')">確定</el-button> -->
        <loadingBtn ref="loadingBtn" @clickHandle="submitForm('form')" />
        <el-button @click="fnBack"> 取消 </el-button>
        <ul class="tips">
          <li>預計兩小時完成審核，政企簽名預計在 48 小時工作時間內審核</li>
          <li>審核工作時間：周一至周日 9:00-23:00（法定節日順延）</li>
        </ul>
      </el-form-item>
    </el-form>
    <!-- 圖片選擇 -->
    <imgPicker
      :dialog-visible="imgDialog"
      :sc-status="isGetImage"
      @chooseImg="pickImg"
      @closeImgDialog="closeImgDialog"
    />

    <!-- result -->
    <el-dialog :visible="resultVisible" class="result" :show-close="false">
      <el-result icon="success" title="提交成功" sub-title="請根據提示進行操作">
        <template slot="subTitle">
          <h5>模組已提交審核，審核結果可在模組列表中查看。</h5>
          <ul class="tips">
            <li>預計兩小時完成審核，政企簽名預計在 48 小時工作時間內審核</li>
            <li>審核工作時間：周一至周日 9:00-23:00（法定節日順延）</li>
          </ul>
        </template>
        <template slot="extra">
          <el-button type="primary" size="medium" @click="fnBack"> 返回列表 </el-button>
          <el-button v-if="!$route.query.type" size="medium" @click="fnAgain">
            再新增一個模組
          </el-button>
        </template>
      </el-result>
    </el-dialog>
  </div>
</template>

<script>
import { requiredRules, MaxRules, MinRules } from '@/utils/validate'
import imgPicker from '@/components/imageselect'
import loadingBtn from '@/components/loading-btn'
import {
  getTemplateSeleteList,
  getTemplateContentLabel,
  addSmsTemplate,
  SmsTemplateDetail,
  editSmsTemplate
} from '@/api/sms'

export default {
  components: {
    imgPicker,
    loadingBtn
  },
  data() {
    return {
      // 頁面狀態
      disabled: false,
      // 圖片選擇
      imgDialog: false,
      isGetImage: false,
      pickerImgType: '',
      // result
      resultVisible: false,

      //
      form: {
        template_type: '',
        scene_id: '',
        template_name: '',
        template_content: '',
        remark: ''
      },
      rules: {
        template_type: [requiredRules('短信類型', 'change')],
        scene_id: [requiredRules('短信場景'), 'change'],
        template_name: [requiredRules('模組名稱')],
        template_content: [requiredRules('模組內容'), MaxRules(500), MinRules(1)],
        remark: [requiredRules('申請說明'), MaxRules(200)]
      },
      template_type_options: [],
      variables: [], //可用的模組變量

      // 頁面 edit 狀態下 判斷是否是首頁加載 首次加載不用清空關聯項
      isEditFirst: true
    }
  },
  watch: {
    async 'form.template_type'(template_type) {
      const result = await getTemplateSeleteList({ template_type })
      let new_arr = result.data.data.list.filter((el) => el.scene_name != '訂單提貨碼')
      this.template_type_options = new_arr
      // 如是創建狀態  把關聯狀態都清空
      const { type } = this.$route.query
      if (type == 'detail' || (type == 'edit' && this.isEditFirst)) {
        return (this.isEditFirst = false)
      }
      this.form.scene_id = ''
      this.form.template_content = ''
      this.variables = []
    },
    async 'form.scene_id'(id) {
      console.log(id, `============`)
      if (!id) return
      const result = await getTemplateContentLabel({ id })
      this.variables = result.data.data.variables
      if (this.$route.query.type == 'edit' || this.$route.query.type == 'detail') {
        return
      }
      this.form.template_content = result.data.data.default_template
      // console.log(result);
    }
  },
  mounted() {
    this.init()
  },
  methods: {
    async init() {
      const { type, id } = this.$route.query
      console.log(type, id)

      if (type) {
        const result = await SmsTemplateDetail({ id })
        this.resultHandler(result)
        if (type == 'detail') {
          this.disabled = true
        }
      }
    },
    resultHandler(result) {
      console.log(result)
      const { template_type, scene_id, template_name, template_content, remark } = result.data.data
      console.log(template_content)
      this.form = {
        template_type,
        scene_id: scene_id + '',
        template_name,
        template_content,
        remark
      }

      console.log(this.form)
    },
    submitForm(formName) {
      const { type, id } = this.$route.query
      this.$refs[formName].validate(async (valid) => {
        if (valid) {
          try {
            if (type == 'edit') {
              const result = await editSmsTemplate({ id, ...this.form })
              this.submitFormResult(result)
            } else {
              // 增加
              const result = await addSmsTemplate(this.form)

              this.submitFormResult(result)
            }
          } catch (error) {
            this.$refs['loadingBtn'].closeLoading()
          }
        } else {
          console.log('error submit!!')
          this.$refs['loadingBtn'].closeLoading()
          return false
        }
      })
    },
    submitFormResult(result) {
      if (result.data.data.status) {
        this.resultVisible = true
      }
      this.$refs['loadingBtn'].closeLoading()
    },
    fnBack() {
      this.$router.push({
        path: `/setting/datamessage/ali_sms/sms_template`
      })
    },
    fnAgain() {
      this.resultVisible = false
      this.$refs['form'].resetFields()
    },
    /* -------------------------圖片選擇------------------------- */
    pickImg({ url }) {
      if (url && this.pickerImgType) {
        const that = this.form
        that[this.pickerImgType] = url
        this.imgDialog = false
      }
    },
    closeImgDialog() {
      this.imgDialog = false
      this.isGetImage = false
    },
    handleImgPicker(pickerImgType) {
      if (!this.disabled) {
        this.pickerImgType = pickerImgType
        this.imgDialog = true
        this.isGetImage = true
      }
    },
    /* -------------------------圖片選擇------------------------- */

    fnKey(item) {
      const { type } = this.$route.query
      if (type == 'detail') return
      console.log(item)
      this.form.template_content = this.form.template_content + ' ${' + item.var_title + '}' + ' '
    }
  }
}
</script>

